+  private getCursorSort(orderBy: any): {
+    field: string;
+    direction: 'asc' | 'desc';
+  }[] {
+    const entries = (Array.isArray(orderBy) ? orderBy : [orderBy]).flatMap(
+      (part) => Object.entries(part || {}),
+    );
+    if (!entries.length) {
+      throw new BadRequestException('cursor orderBy must include at least one field');
+    }
+    return entries.map(([field, value]) => {
+      const direction = value?.toString().toLowerCase();
+      if (direction !== 'asc' && direction !== 'desc') {
+        throw new BadRequestException('cursor only supports asc or desc orderBy directions');
+      }
+      return { field, direction };
+    });
+  }
+
+  private decodeCursor(cursor: string): Record<string, any> {
+    try {
+      const parsed = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+      if (!parsed || Array.isArray(parsed) || typeof parsed !== 'object') {
+        throw new Error('Cursor payload must be an object');
+      }
+      return parsed;
+    } catch {
+      throw new BadRequestException('cursor must be valid Base64 JSON');
+    }
+  }
+
+  private validateCursor(
+    cursor: Record<string, any>,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    const expectedSort = sort
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    if (cursor.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    if (!(this.crudConfig.id_field in cursor)) {
+      throw new BadRequestException('cursor is missing the entity ID');
+    }
+    for (const { field } of sort) {
+      if (!(field in cursor)) {
+        throw new BadRequestException(`cursor is missing sort field ${field}`);
+      }
+    }
+  }
+
+  private makeCursorQuery(
+    entity: Partial<T>,
+    cursor: Record<string, any>,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ): Partial<T> {
+    const comparisons = sort.map(({ field, direction }, index) => ({
+      $and: [
+        ...sort.slice(0, index).map(({ field }) => ({ [field]: cursor[field] })),
+        { [field]: { [direction === 'asc' ? '$gt' : '$lt']: cursor[field] } },
+      ],
+    }));
+    return { $and: [entity, { $or: comparisons }] } as Partial<T>;
+  }
+
+  private encodeCursor(
+    entity: T,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ): string {
+    const cursor = sort.reduce(
+      (data, { field }) => ({ ...data, [field]: entity[field] }),
+      {},
+    );
+    cursor.__sort = sort
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
